const location = global.get('config')?.location;
const lat = location?.latitude;
const lon = location?.longitude;

msg.url = `https://api.weather.gov/alerts/active?point=${lat},${lon}`;

msg.headers = { 
    'Accept': 'application/geo+json',
    'User-Agent': global.get('config')?.system?.http?.user_agent
};

msg.payload = '';
return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const location = global.get('config')?.location;
const lat = location?.latitude;
const lon = location?.longitude;

if (msg.statusCode !== 200) {
    node.error(`Alerts fetch failed: ${msg.statusCode}`, msg);
    return null;
}

const incoming = msg.payload.features || [];
const known = flow.get('known_alerts') || {};
const now = new Date();

const severityMap = {
    'Extreme': 'critical',
    'Severe': 'high',
    'Moderate': 'medium',
    'Minor': 'low'
};

const events = [];
const updatedKnown = {};

// Process incoming alerts
for (const feature of incoming) {
    const p = feature.properties;
    const id = p.id;
    const existing = known[id];

    updatedKnown[id] = {
        sent: p.sent,
        event: p.event,
        severity: p.severity,
        headline: p.headline,
        ends: p.ends
    };

    const eventPayload = {
        timestamp: now.toISOString(),
        source: 'weather_alerts',
        event: p.event,
        headline: p.headline,
        severity: p.severity,
        notification_severity: severityMap[p.severity] || 'medium',
        sent: p.sent,
        ends: p.ends,
        url: `https://forecast.weather.gov/MapClick.php?lat=${lat}&lon=${lon}`
    };

    if (!existing) {
        // New alert
        events.push({ topic: 'highland/event/weather/alert/new', payload: eventPayload });
    } else if (existing.sent !== p.sent) {
        // Updated alert
        events.push({ topic: 'highland/event/weather/alert/updated', payload: eventPayload });
    }
    // Otherwise ongoing — no event
}

// Check for expired alerts
for (const [id, data] of Object.entries(known)) {
    if (!updatedKnown[id]) {
        const endsTime = data.ends ? new Date(data.ends) : null;
        if (!endsTime || endsTime <= now) {
            events.push({
                topic: 'highland/event/weather/alert/expired',
                payload: {
                    timestamp: now.toISOString(),
                    source: 'weather_alerts',
                    event: data.event,
                    headline: data.headline,
                    severity: data.severity,
                    ends: data.ends
                }
            });
        } else {
            // Ends in future but not in response — keep in known for now
            updatedKnown[id] = data;
        }
    }
}

// Persist updated known set
flow.set('known_alerts', updatedKnown);

// Build snapshot payload
const activeAlerts = Object.values(updatedKnown).map(a => ({
    event: a.event,
    headline: a.headline,
    severity: a.severity,
    ends: a.ends
}));

const snapshot = {
    topic: 'highland/state/weather/alerts',
    retain: true,
    qos: 1,
    payload: JSON.stringify({
        timestamp: now.toISOString(),
        source: 'weather_alerts',
        alerts: activeAlerts
    })
};

// Status — only update on change
const previousCount = flow.get('last_alert_count') ?? -1;
const currentCount = activeAlerts.length;
if (currentCount !== previousCount) {
    flow.set('last_alert_count', currentCount);
}

node.status({
    fill: currentCount > 0 ? 'yellow' : 'green',
    shape: currentCount > 0 ? 'ring' : 'dot',
    text: formatStatus(`${currentCount} active alert(s)`)
});

msg.snapshot = snapshot;
msg.events = events;
return msg;

// Always publish snapshot
node.send({ topic: msg.snapshot.topic, payload: msg.snapshot.payload, retain: true, qos: 1 });

// Fire any lifecycle events
for (const evt of msg.events) {
    node.send({ topic: evt.topic, payload: JSON.stringify(evt.payload), retain: false, qos: 0 });
}

return null;
